import type { ApiVersion, DataModelModule, Handle } from "./ExtensionHost.js";
import type { DataModelObject } from "./DataModelObject.js";
import type { DataModelObjectRegistry } from "./DataModelObjectRegistry.js";

/**
 * Invokes an asynchronous data model function inside a transaction, returning
 * a promise that resolves when its `onResult` callback fires (or rejects when
 * `onError` is invoked).
 *
 *  @internal
 */
export const invokeAsync = <V extends ApiVersion, Args extends unknown[]>(
  dataModel: DataModelModule<V>,
  fn: (...args: [...Args, () => void, () => void]) => void,
  ...args: Args
): Promise<void> =>
  new Promise<void>((resolve, reject) => {
    dataModel.withinTransaction(() => fn(...args, resolve, reject));
  });

/**
 * Like {@link invokeAsync}, but for data model functions whose `onResult`
 * yields a {@link Handle}. The handle is wrapped as an instance of `T` via
 * the object registry before the promise resolves.
 *
 * @internal
 */
export const createAsync = <
  V extends ApiVersion,
  Args extends unknown[],
  T extends DataModelObject<V>,
>(
  dataModel: DataModelModule<V>,
  registry: DataModelObjectRegistry<V>,
  type: abstract new (...args: never) => T,
  fn: (...args: [...Args, (handle: Handle) => void, () => void]) => void,
  ...args: Args
): Promise<T> =>
  new Promise<T>((resolve, reject) => {
    dataModel.withinTransaction(() =>
      fn(
        ...args,
        (handle) => resolve(registry.getObjectFromHandle(handle, type)),
        reject,
      ),
    );
  });
