import type { ApiVersion, ClipLoopSettings } from "./ExtensionHost.js";
import { createAsync, invokeAsync } from "./transaction.js";
import { AudioClip } from "./AudioClip.js";
import { Clip } from "./Clip.js";
import { DataModelObject } from "./DataModelObject.js";
import { MidiClip } from "./MidiClip.js";

/** A slot in the Session View grid that can hold a clip. */
export class ClipSlot<
  Version extends ApiVersion,
> extends DataModelObject<Version> {
  static readonly className = "ClipSlot";

  get clip() {
    const handle = this.dataModel.clipslotGetClip(this.handle);
    return handle
      ? this.objectRegistry.getObjectFromHandle(handle, Clip<Version>)
      : null;
  }

  /**
   * Deletes the clip in this slot. Await the returned promise to ensure the
   * deletion has been fully processed.
   */
  deleteClip() {
    return invokeAsync(
      this.dataModel,
      this.dataModel.clipslotDeleteClip,
      this.handle,
    );
  }

  /** @param length - Length of the clip in beats. */
  createMidiClip(length: number) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      MidiClip<Version>,
      this.dataModel.clipslotCreateMidiClip,
      this.handle,
      length,
    );
  }

  /**
   * Creates an audio clip in this session slot.
   *
   * @param args.filePath - Absolute path to the audio file.
   * @param args.isWarped - See {@link AudioTrack.createAudioClip}.
   * @param args.loopSettings - See {@link AudioTrack.createAudioClip}.
   */
  createAudioClip(args: {
    filePath: string;
    isWarped?: boolean;
    loopSettings?: ClipLoopSettings;
  }) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      AudioClip<Version>,
      this.dataModel.clipslotCreateAudioClip,
      this.handle,
      {
        filePath: args.filePath,
        isWarped: args.isWarped,
        loopSettings: args.loopSettings,
      },
    );
  }
}
