import type { ApiVersion } from "./ExtensionHost.js";
import { DataModelObject } from "./DataModelObject.js";
import { DeviceParameter } from "./DeviceParameter.js";

/** Represents the mixer of a device chain. */
export class ChainMixer<
  Version extends ApiVersion,
> extends DataModelObject<Version> {
  static readonly className = "ChainMixerDevice";

  get volume() {
    return this.objectRegistry.getObjectFromHandle(
      this.dataModel.chainmixerdeviceGetVolume(this.handle),
      DeviceParameter<Version>,
    );
  }

  get panning() {
    return this.objectRegistry.getObjectFromHandle(
      this.dataModel.chainmixerdeviceGetPanning(this.handle),
      DeviceParameter<Version>,
    );
  }

  get sends() {
    return this.dataModel
      .chainmixerdeviceGetSends(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(
          handle,
          DeviceParameter<Version>,
        ),
      );
  }
}
