import type { ApiVersion, ClipLoopSettings } from "./ExtensionHost.js";
import { AudioClip } from "./AudioClip.js";
import { Clip } from "./Clip.js";
import { DataModelObject } from "./DataModelObject.js";
import { MidiClip } from "./MidiClip.js";
import { createAsync } from "./transaction.js";

/** Represents a take lane. */
export class TakeLane<
  Version extends ApiVersion,
> extends DataModelObject<Version> {
  static readonly className = "TakeLane";

  get clips() {
    return this.dataModel
      .takelaneGetClips(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, Clip<Version>),
      );
  }

  get name() {
    return this.dataModel.takelaneGetName(this.handle);
  }

  set name(value: string) {
    this.dataModel.withinTransaction(() => {
      this.dataModel.takelaneSetName(this.handle, value);
    });
  }

  /**
   * @param startTime - Position in the arrangement in beats.
   * @param duration - Length of the clip in beats.
   */
  createMidiClip(startTime: number, duration: number) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      MidiClip<Version>,
      this.dataModel.takelaneCreateMidiClip,
      this.handle,
      startTime,
      duration,
    );
  }

  /**
   * Creates an audio clip on this take lane. See {@link AudioTrack.createAudioClip}
   * for argument semantics.
   */
  createAudioClip(args: {
    filePath: string;
    startTime: number;
    duration?: number;
    isWarped?: boolean;
    loopSettings?: ClipLoopSettings;
  }) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      AudioClip<Version>,
      this.dataModel.takelaneCreateAudioClip,
      this.handle,
      {
        duration: args.duration,
        filePath: args.filePath,
        isWarped: args.isWarped,
        loopSettings: args.loopSettings,
        startTime: args.startTime,
      },
    );
  }
}
