import { createAsync, invokeAsync } from "./transaction.js";
import type { ApiVersion } from "./ExtensionHost.js";
import { AudioTrack } from "./AudioTrack.js";
import { CuePoint } from "./CuePoint.js";
import { DataModelObject } from "./DataModelObject.js";
import { MidiTrack } from "./MidiTrack.js";
import { Scene } from "./Scene.js";
import { Track } from "./Track.js";

/** Represents the current Live Set. */
export class Song<Version extends ApiVersion> extends DataModelObject<Version> {
  static readonly className = "Song";

  /** Regular tracks only — excludes return tracks and the main track. */
  get tracks() {
    return this.dataModel
      .songGetTracks(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, Track<Version>),
      );
  }

  get returnTracks() {
    return this.dataModel
      .songGetReturnTracks(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, Track<Version>),
      );
  }

  get mainTrack() {
    return this.objectRegistry.getObjectFromHandle(
      this.dataModel.songGetMainTrack(this.handle),
      Track<Version>,
    );
  }

  get scenes() {
    return this.dataModel
      .songGetScenes(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, Scene<Version>),
      );
  }

  get cuePoints() {
    return this.dataModel
      .songGetCuePoints(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, CuePoint<Version>),
      );
  }

  get tempo() {
    return this.dataModel.songGetTempo(this.handle);
  }

  set tempo(value: number) {
    this.dataModel.withinTransaction(() => {
      this.dataModel.songSetTempo(this.handle, value);
    });
  }

  /**
   * The current arrangement grid quantization. Use with {@link gridIsTriplet} to
   * determine the full grid setting.
   */
  get gridQuantization() {
    return this.dataModel.songGetGridQuantization(this.handle);
  }

  /**
   * Whether the arrangement grid uses triplet subdivisions of the current
   * {@link gridQuantization} value.
   */
  get gridIsTriplet() {
    return this.dataModel.songGetGridIsTriplet(this.handle);
  }

  /**
   * The root note of the scale currently selected in Live, as a MIDI note number
   * from 0 (C) to 11 (B).
   */
  get rootNote() {
    return Number(this.dataModel.songGetRootNote(this.handle));
  }

  /** The name of the scale selected in Live, as shown in the Current Scale Name chooser. */
  get scaleName() {
    return this.dataModel.songGetScaleName(this.handle);
  }

  /** Whether Live's Scale Mode is enabled. */
  get scaleMode() {
    return this.dataModel.songGetScaleMode(this.handle);
  }

  /** The intervals of the current scale as semitone offsets from the root note. */
  get scaleIntervals() {
    return this.dataModel.songGetScaleIntervals(this.handle).map(Number);
  }

  /** Inserted after the last selected track, or appended if no track is selected. */
  createAudioTrack() {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      AudioTrack<Version>,
      this.dataModel.songCreateAudioTrack,
      this.handle,
    );
  }

  /** Inserted after the last selected track, or appended if no track is selected. */
  createMidiTrack() {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      MidiTrack<Version>,
      this.dataModel.songCreateMidiTrack,
      this.handle,
    );
  }

  /**
   * @param index - 0-based insert position in the range `[0, song.scenes.length]`.
   * Pass `-1` to append at the end.
   */
  createScene(index: number) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      Scene<Version>,
      this.dataModel.songCreateScene,
      this.handle,
      BigInt(index),
    );
  }

  /**
   * Deletes a track from the song. Await the returned promise to ensure the
   * deletion has been fully processed.
   */
  deleteTrack(track: Track<Version>) {
    return invokeAsync(
      this.dataModel,
      this.dataModel.songDeleteTrack,
      this.handle,
      track.handle,
    );
  }

  /**
   * Deletes a scene from the song. Await the returned promise to ensure the
   * deletion has been fully processed.
   */
  deleteScene(scene: Scene<Version>) {
    return invokeAsync(
      this.dataModel,
      this.dataModel.songDeleteScene,
      this.handle,
      scene.handle,
    );
  }

  /** Duplicates the track. The duplicate is inserted immediately after the original. */
  duplicateTrack(track: Track<Version>) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      Track<Version>,
      this.dataModel.songDuplicateTrack,
      this.handle,
      track.handle,
    );
  }

  /** Duplicates the scene. The duplicate is inserted immediately after the original. */
  duplicateScene(scene: Scene<Version>) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      Scene<Version>,
      this.dataModel.songDuplicateScene,
      this.handle,
      scene.handle,
    );
  }

  /** @param time - Position in the arrangement in beats. */
  createCuePoint(time: number) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      CuePoint<Version>,
      this.dataModel.songCreateCuePoint,
      this.handle,
      time,
    );
  }

  /**
   * Deletes a cue point from the song. Await the returned promise to ensure
   * the deletion has been fully processed.
   */
  deleteCuePoint(cuePoint: CuePoint<Version>) {
    return invokeAsync(
      this.dataModel,
      this.dataModel.songDeleteCuePoint,
      this.handle,
      cuePoint.handle,
    );
  }
}
