import type { ApiVersion, DataModelModule, Handle } from "./ExtensionHost.js";
import { Application } from "./Application.js";
import { AudioClip } from "./AudioClip.js";
import { AudioTrack } from "./AudioTrack.js";
import { Chain } from "./Chain.js";
import { ChainMixer } from "./ChainMixer.js";
import { Clip } from "./Clip.js";
import { ClipSlot } from "./ClipSlot.js";
import { CuePoint } from "./CuePoint.js";
import type { DataModelObject } from "./DataModelObject.js";
import { Device } from "./Device.js";
import { DeviceParameter } from "./DeviceParameter.js";
import { DrumChain } from "./DrumChain.js";
import { DrumRack } from "./DrumRack.js";
import { MidiClip } from "./MidiClip.js";
import { MidiTrack } from "./MidiTrack.js";
import { RackDevice } from "./RackDevice.js";
import { Sample } from "./Sample.js";
import { Scene } from "./Scene.js";
import { Simpler } from "./Simpler.js";
import { Song } from "./Song.js";
import { TakeLane } from "./TakeLane.js";
import { Track } from "./Track.js";
import { TrackMixer } from "./TrackMixer.js";

const dataModelClasses = [
  Application,
  Song,
  AudioTrack,
  MidiTrack,
  Track,
  AudioClip,
  MidiClip,
  Clip,
  ClipSlot,
  TakeLane,
  Simpler,
  DrumRack,
  RackDevice,
  Device,
  Sample,
  DrumChain,
  Chain,
  Scene,
  CuePoint,
  DeviceParameter,
  TrackMixer,
  ChainMixer,
];

/**
 * Resolves {@link Handle}s into typed SDK objects.
 *
 * Objects are cached by handle ID, so the same Live object always returns the same SDK instance.
 */
export class DataModelObjectRegistry<Version extends ApiVersion> {
  private cache = new Map<bigint, DataModelObject<Version>>();
  private dataModel: DataModelModule<Version>;

  /** @internal */
  constructor(dataModel: DataModelModule<Version>) {
    this.dataModel = dataModel;
  }

  private getOrCreateObjectFromHandle(
    handle: Handle,
  ): DataModelObject<Version> {
    const cached = this.cache.get(handle.id);
    if (cached) {
      return cached;
    }

    const ModelClass = dataModelClasses.find((cls) =>
      this.dataModel.getObjectIsOfClass(handle, cls.className),
    );

    if (!ModelClass) {
      throw new Error("Unknown object type");
    }

    const obj = new ModelClass(handle, this.dataModel, this);
    this.cache.set(handle.id, obj);
    return obj;
  }

  /**
   * Resolves a {@link Handle} into a typed SDK object.
   *
   * Pass {@link DataModelObject} as `type` when the exact type of the handle is not known
   * in advance, then use `instanceof` to branch on the actual type:
   *
   * ```ts
   * const obj = objects.getObjectFromHandle(handle, DataModelObject);
   * if (obj instanceof ClipSlot) {
   *   // ...
   * }
   * ```
   *
   * Throws if the underlying object has been deleted, if it is of a different
   * type than `type`, or if its type is not recognised.
   *
   * @param handle - The handle to resolve.
   * @param type - The expected SDK class (e.g. `ClipSlot`).
   */
  getObjectFromHandle<T extends DataModelObject<Version>>(
    handle: Handle,
    type: abstract new (...args: never) => T,
  ): T {
    const obj = this.getOrCreateObjectFromHandle(handle);
    if (!(obj instanceof type)) {
      throw new Error("Object of incorrect type");
    }
    return obj;
  }
}
