import { createAsync, invokeAsync } from "./transaction.js";
import type { ApiVersion } from "./ExtensionHost.js";
import { Clip } from "./Clip.js";
import { ClipSlot } from "./ClipSlot.js";
import { DataModelObject } from "./DataModelObject.js";
import { Device } from "./Device.js";
import { TakeLane } from "./TakeLane.js";
import { TrackMixer } from "./TrackMixer.js";

/** Represents a track. */
export class Track<
  Version extends ApiVersion,
> extends DataModelObject<Version> {
  static readonly className: string = "Track";

  get name() {
    return this.dataModel.trackGetName(this.handle);
  }

  set name(value: string) {
    this.dataModel.withinTransaction(() => {
      this.dataModel.trackSetName(this.handle, value);
    });
  }

  get mute() {
    return this.dataModel.trackGetMute(this.handle);
  }

  set mute(value: boolean) {
    this.dataModel.withinTransaction(() => {
      this.dataModel.trackSetMute(this.handle, value);
    });
  }

  get solo() {
    return this.dataModel.trackGetSolo(this.handle);
  }

  set solo(value: boolean) {
    this.dataModel.withinTransaction(() => {
      this.dataModel.trackSetSolo(this.handle, value);
    });
  }

  get mutedViaSolo() {
    return this.dataModel.trackGetMutedViaSolo(this.handle);
  }

  get arm() {
    return this.dataModel.trackGetArm(this.handle);
  }

  set arm(value: boolean) {
    this.dataModel.withinTransaction(() => {
      this.dataModel.trackSetArm(this.handle, value);
    });
  }

  get clipSlots() {
    return this.dataModel
      .trackGetClipSlots(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, ClipSlot<Version>),
      );
  }

  get takeLanes() {
    return this.dataModel
      .trackGetTakeLanes(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, TakeLane<Version>),
      );
  }

  get arrangementClips() {
    return this.dataModel
      .trackGetArrangementClips(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, Clip<Version>),
      );
  }

  get groupTrack(): Track<Version> | null {
    const handle = this.dataModel.trackGetGroupTrack(this.handle);
    return handle
      ? this.objectRegistry.getObjectFromHandle(handle, Track<Version>)
      : null;
  }

  get devices() {
    return this.dataModel
      .trackGetDevices(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, Device<Version>),
      );
  }

  get mixer() {
    return this.objectRegistry.getObjectFromHandle(
      this.dataModel.trackGetMixerDevice(this.handle),
      TrackMixer<Version>,
    );
  }

  /** Appended to the end of {@link takeLanes}. */
  createTakeLane() {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      TakeLane<Version>,
      this.dataModel.trackCreateTakeLane,
      this.handle,
    );
  }

  /**
   * Inserts a built-in Live device with its default preset into the track's device chain.
   * Only devices native to Live are supported — third-party plug-ins cannot be loaded this way.
   *
   * @param deviceName - The name of the built-in Live device (e.g. `"Reverb"`, `"Auto Filter"`).
   * @param index - Zero-based position in the device chain at which to insert.
   */
  insertDevice(deviceName: string, index: number) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      Device<Version>,
      this.dataModel.trackInsertDevice,
      this.handle,
      deviceName,
      BigInt(index),
    );
  }

  /**
   * Deletes a device from this track's device chain. Await the returned
   * promise to ensure the deletion has been fully processed.
   */
  deleteDevice(device: Device<Version>) {
    return invokeAsync(
      this.dataModel,
      this.dataModel.trackDeleteDevice,
      this.handle,
      device.handle,
    );
  }

  /** The duplicate is inserted directly after the original in the device chain. */
  duplicateDevice(device: Device<Version>) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      Device<Version>,
      this.dataModel.trackDuplicateDevice,
      this.handle,
      device.handle,
    );
  }

  /**
   * Deletes an arrangement clip. For session clips, use {@link ClipSlot.deleteClip}.
   * Await the returned promise to ensure the deletion has been fully processed.
   */
  deleteClip(clip: Clip<Version>) {
    return invokeAsync(
      this.dataModel,
      this.dataModel.trackDeleteClip,
      this.handle,
      clip.handle,
    );
  }

  /**
   * Deletes clips within the range. Clips that overlap a boundary are truncated
   * to the range edge rather than fully deleted.
   *
   * @param startTime - Start of the range in beats.
   * @param endTime - End of the range in beats.
   */
  clearClipsInRange(startTime: number, endTime: number) {
    return invokeAsync(
      this.dataModel,
      this.dataModel.trackClearClipsInRange,
      this.handle,
      startTime,
      endTime,
    );
  }
}
