import type { ApiVersion, NoteDescription } from "./ExtensionHost.js";
import { Clip } from "./Clip.js";

/** Represents a MIDI clip. */
export class MidiClip<Version extends ApiVersion> extends Clip<Version> {
  static override readonly className = "MidiClip";

  get notes() {
    return this.dataModel.midiclipGetNotes(this.handle);
  }

  set notes(notes: NoteDescription[]) {
    this.dataModel.withinTransaction(() => {
      this.dataModel.midiclipSetNotes(this.handle, notes);
    });
  }
}
