import type { ApiVersion } from "./ExtensionHost.js";
import { Device } from "./Device.js";
import { Sample } from "./Sample.js";
import { createAsync } from "./transaction.js";

/** Represents a Simpler device. */
export class Simpler<Version extends ApiVersion> extends Device<Version> {
  static override readonly className = "Simpler";

  get sample() {
    const handle = this.dataModel.simplerGetSample(this.handle);
    return handle
      ? this.objectRegistry.getObjectFromHandle(handle, Sample<Version>)
      : null;
  }

  /** Replaces the loaded sample with the audio file at the given absolute path. */
  replaceSample(filePath: string) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      Sample<Version>,
      this.dataModel.simplerReplaceSample,
      this.handle,
      filePath,
    );
  }
}
