import type { ApiVersion } from "./ExtensionHost.js";
import { Chain } from "./Chain.js";

/** Represents a drum chain. */
export class DrumChain<Version extends ApiVersion> extends Chain<Version> {
  static override readonly className = "DrumChain";

  get receivingNote() {
    return Number(this.dataModel.drumchainGetReceivingNote(this.handle));
  }

  set receivingNote(value: number) {
    this.dataModel.withinTransaction(() => {
      this.dataModel.drumchainSetReceivingNote(this.handle, BigInt(value));
    });
  }
}
