import type { ApiVersion } from "./ExtensionHost.js";
import { MidiClip } from "./MidiClip.js";
import { Track } from "./Track.js";
import { createAsync } from "./transaction.js";

/** Represents a MIDI track. */
export class MidiTrack<Version extends ApiVersion> extends Track<Version> {
  static override readonly className = "MidiTrack";

  /**
   * @param startTime - Position in the arrangement in beats.
   * @param duration - Length of the clip in beats.
   */
  createMidiClip(startTime: number, duration: number) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      MidiClip<Version>,
      this.dataModel.trackCreateMidiClip,
      this.handle,
      startTime,
      duration,
    );
  }
}
