import type { ApiVersion } from "./ExtensionHost.js";
import { Chain } from "./Chain.js";
import { Device } from "./Device.js";
import { createAsync } from "./transaction.js";

/** Represents a rack device. */
export class RackDevice<Version extends ApiVersion> extends Device<Version> {
  static override readonly className: string = "RackDevice";

  get chains() {
    return this.dataModel
      .rackdeviceGetChains(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, Chain<Version>),
      );
  }

  /** @param index - 0-based insert position in the range `[0, rack.chains.length]`. */
  insertChain(index: number) {
    return createAsync(
      this.dataModel,
      this.objectRegistry,
      Chain<Version>,
      this.dataModel.rackdeviceInsertChain,
      this.handle,
      BigInt(index),
    );
  }
}
