// Versioned API surface, keyed by version string. To add a new version:
// 1. Define `ExtensionsApi_X_Y_Z` (or alias an older one if the shape is
//    unchanged).
// 2. Add an entry to `EXTENSIONS_API` below.
// 3. Prepend the new version to `EXTENSIONS_API_VERSIONS` (newest first).
/** @internal */
export type EXTENSIONS_API = {
  "1.0.0": ExtensionsApi_1_0_0;
};

// Newest-first tuple. Doubles as a type (for indexing) and a runtime const.
/** @internal */
export type EXTENSIONS_API_VERSIONS = ["1.0.0"];
/** All API versions supported by this SDK release, newest first. */
export const EXTENSIONS_API_VERSIONS: EXTENSIONS_API_VERSIONS = ["1.0.0"];

/** @internal */
export type ApiVersion = keyof EXTENSIONS_API;

/** @internal */
export type CommandsModule<V extends ApiVersion> =
  EXTENSIONS_API[V]["commands"];
export type DataModelModule<V extends ApiVersion> =
  EXTENSIONS_API[V]["dataModel"];
export type EnvironmentModule<V extends ApiVersion> =
  EXTENSIONS_API[V]["environment"];
export type ResourcesModule<V extends ApiVersion> =
  EXTENSIONS_API[V]["resources"];
export type UiModule<V extends ApiVersion> = EXTENSIONS_API[V]["ui"];

/**
 * The scope in which a context menu action is shown.
 *
 * Scopes that pass the triggered object's {@link Handle} as the first command argument:
 * `"AudioClip"`, `"AudioTrack"`, `"ClipSlot"`, `"DrumRack"`, `"MidiClip"`,`"MidiTrack"`,
 * `"Sample"`, `"Scene"`, `"Simpler"`.
 *
 * Scopes that pass a selection context as the first command argument:
 * `"ClipSlotSelection"` ({@link ClipSlotSelection}),
 * `"AudioTrack.ArrangementSelection"` and `"MidiTrack.ArrangementSelection"` ({@link ArrangementSelection}).
 */
export type ContextMenuScope<V extends ApiVersion> = V extends "1.0.0"
  ?
      | "AudioClip"
      | "AudioTrack"
      | "ClipSlot"
      | "DrumRack"
      | "MidiClip"
      | "MidiTrack"
      | "Sample"
      | "Scene"
      | "Simpler"
      | "ClipSlotSelection"
      | "AudioTrack.ArrangementSelection"
      | "MidiTrack.ArrangementSelection"
  : never;

/** @internal */
export interface InitializeOptions<V extends ApiVersion> {
  apiVersion: V;
}

/**
 * The context passed to your extension's `activate` function. Pass it to {@link initialize} to set up the SDK.
 */
export interface ActivationContext {
  /** The latest API version the Extension Host supports. */
  hostApiVersion: string;
  /** @internal */
  initializeExtensionHost<V extends ApiVersion>(
    options: InitializeOptions<V>,
  ): EXTENSIONS_API[V];
}
