import type { ApiVersion } from "./ExtensionHost.js";
import { DrumChain } from "./DrumChain.js";
import { RackDevice } from "./RackDevice.js";

/** Represents a Drum Rack device. */
export class DrumRack<Version extends ApiVersion> extends RackDevice<Version> {
  static override readonly className = "DrumRackDevice";

  override get chains() {
    return this.dataModel
      .rackdeviceGetChains(this.handle)
      .map((handle) =>
        this.objectRegistry.getObjectFromHandle(handle, DrumChain<Version>),
      );
  }
}
