import type { ApiVersion } from "./ExtensionHost.js";
import { DataModelObject } from "./DataModelObject.js";

/** Represents a cue point. */
export class CuePoint<
  Version extends ApiVersion,
> extends DataModelObject<Version> {
  static readonly className = "CuePoint";

  get time() {
    return this.dataModel.cuePointGetTime(this.handle);
  }

  get name() {
    return this.dataModel.cuePointGetName(this.handle);
  }

  set name(value: string) {
    this.dataModel.withinTransaction(() => {
      this.dataModel.cuePointSetName(this.handle, value);
    });
  }
}
